#include <stdio.h>
#include <stdlib.h>

int main() {
    int N, M, w, b;
    scanf("%d %d %d %d", &N, &M, &w, &b);
    int** grid = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        grid[i] = (int*)malloc(M * sizeof(int));
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            grid[i][j] = 0;
        }
    }
    for (int i = 0; i < w; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        grid[x - 1][y - 1] = 1;
    }
    for (int i = 0; i < b; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        grid[x - 1][y - 1] = 2;
    }
    long long sum = 0;
    for (int i = 0; i < N; i++) {
        int wCount = 0;
        for (int j = 0; j < M; j++) {
            if (grid[i][j] == 0) {
                sum += j + 1;
            } else if (grid[i][j] == 1) {
                wCount++;
                if (wCount == 2) {
                    break;
                }
            } else {
                break;
            }
        }
    }
    printf("%lld\n", sum);
    return 0;
}

